ion": "Knee Push-Up"}, {"name": "Lat Pulldown", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 10, "rest_seconds": 90, "weight_guidance": "Light weight, focus on pulling with lats", "equipment": "Cable Machine", "body_part": "Back", "primary_muscle": "Latissimus Dorsi", "secondary_muscles": ["Biceps", "Rear Deltoids"], "difficulty": "beginner", "form_cue": "Lean slightly back, pull to upper chest, squeeze lats", "substitution": "Resistance Band Pulldown"}, {"name": "Dumbbell Lateral Raise", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 60, "weight_guidance": "Very light, control the movement", "equipment": "Dumbbells", "body_part": "Shoulders", "primary_muscle": "Lateral Deltoids", "secondary_muscles": ["Upper Trapezius"], "difficulty": "beginner", "form_cue": "Slight bend in elbows, raise to shoulder height, slow lower", "substitution": "Cable Lateral Raise"}, {"name": "Dumbbell Step-Up", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 10, "rest_seconds": 75, "weight_guidance": "Light dumbbells or bodyweight", "equipment": "Dumbbells", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Glutes", "Hamstrings"], "difficulty": "beginner", "form_cue": "Drive through lead foot, full hip extension at top", "substitution": "Leg Press"}, {"name": "Dead Bug", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 10, "rest_seconds": 45, "weight_guidance": "Bodyweight, slow and controlled", "equipment": "None", "body_part": "Core", "primary_muscle": "Rectus Abdominis", "secondary_muscles": ["Obliques", "Hip Flexors"], "difficulty": "beginner", "form_cue": "Press lower back into floor, extend opposite arm and leg slowly", "substitution": "Bird Dog"}]}, {"workout_name": "Day 3 - Full Body C", "type": "strength", "duration_minutes": 45, "exercises": [{"name": "Dumbbell Sumo Squat", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 90, "weight_guidance": "Light dumbbell, wide stance", "equipment": "Dumbbell", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Adductors", "Glutes"], "difficulty": "beginner", "form_cue": "Wide stance, toes out 45 degrees, keep torso upright", "substitution": "Goblet Squat"}, {"name": "Dumbbell Floor Press", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 10, "rest_seconds": 90, "weight_guidance": "Light to moderate dumbbells", "equipment": "Dumbbells", "body_part": "Chest", "primary_muscle": "Pectorals", "secondary_muscles": ["Triceps", "Anterior Deltoids"], "difficulty": "beginner", "form_cue": "Elbows touch floor, press to lockout, stable shoulders", "substitution": "Push-Up"}, {"name": "Single-Arm Dumbbell Row", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 10, "rest_seconds": 75, "weight_guidance": "Light, focus on lat contraction", "equipment": "Dumbbell", "body_part": "Back", "primary_muscle": "Latissimus Dorsi", "secondary_muscles": ["Rhomboids", "Biceps"], "difficulty": "beginner", "form_cue": "One hand on bench, pull elbow to hip, squeeze at top", "substitution": "Cable Row"}, {"name": "Dumbbell Curl", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 60, "weight_guidance": "Light, full range of motion", "equipment": "Dumbbells", "body_part": "Arms", "primary_muscle": "Biceps", "secondary_muscles": ["Brachialis", "Forearms"], "difficulty": "beginner", "form_cue": "Keep elbows pinned, full extension and contraction", "substitution": "Hammer Curl"}, {"name": "Dumbbell Triceps Kickback", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 60, "weight_guidance": "Light, squeeze at extension", "equipment": "Dumbbells", "body_part": "Arms", "primary_muscle": "Triceps", "secondary_muscles": ["Anconeus"], "difficulty": "beginner", "form_cue": "Hinge forward, extend arm fully, pause at top", "substitution"